firmware_template.source:
#include "ssr_relay.h"
#include <Arduino.h>
#define SSR_PIN 25
static bool _on=false;
void ssr_setup(){pinMode(SSR_PIN,OUTPUT);Serial.println("[ssr] OK");}
void ssr_on(){digitalWrite(SSR_PIN,HIGH);_on=true;}
void ssr_off(){digitalWrite(SSR_PIN,LOW);_on=false;}
void ssr_set_duty(uint8_t pct,uint16_t period){uint16_t on_t=period*pct/100;ssr_on();delay(on_t);ssr_off();delay(period-on_t);}
bool ssr_state(){return _on;}
